import{_ as r,o as t,c as o,ae as n}from"./chunks/framework.BGHOrOyn.js";const c=JSON.parse('{"title":"Install Arduino IDE on Raspberry","description":"https://linuxhint.com/install-arduino-ide-raspberry-pi/","frontmatter":{"description":"https://linuxhint.com/install-arduino-ide-raspberry-pi/"},"headers":[],"relativePath":"microcontrollers-and-socs/raspberry-pi/install-arduino-ide-on-raspberry.md","filePath":"microcontrollers-and-socs/raspberry-pi/install-arduino-ide-on-raspberry.md"}'),a={name:"microcontrollers-and-socs/raspberry-pi/install-arduino-ide-on-raspberry.md"};function i(l,e,s,p,u,h){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="install-arduino-ide-on-raspberry" tabindex="-1">Install Arduino IDE on Raspberry <a class="header-anchor" href="#install-arduino-ide-on-raspberry" aria-label="Permalink to &quot;Install Arduino IDE on Raspberry&quot;">​</a></h1><p><a href="https://linuxhint.com/category/raspberry-pi/" target="_blank" rel="noreferrer">Raspberry Pi</a></p><h2 id="how-to-install-arduino-ide-on-raspberry-pi" tabindex="-1">How to Install Arduino IDE on Raspberry Pi <a class="header-anchor" href="#how-to-install-arduino-ide-on-raspberry-pi" aria-label="Permalink to &quot;How to Install Arduino IDE on Raspberry Pi&quot;">​</a></h2><p>1 year agoby <a href="https://linuxhint.com/author/awaiskhan/" target="_blank" rel="noreferrer">Awais Khan</a><br> If you are a university student with friends who are studying electrical engineering, you have most likely heard of Arduino. This is due to the fact that Arduino is a tool that is commonly used by electrical engineering students today to create their projects.</p><p>Let’s use a pencil as an example because it allows you to write something on paper. If you don’t write, it won’t help you and the same is true for Arduino, which works when you program it. Arduino IDE provides you the environment where you can write your codes and check whether they are working fine. You cannot control a device using the Adriano module if you haven’t done proper coding on the IDE. In order to test the code before uploading it on the Arduino module, you will need an IDE for that purpose. If you are able to run your code successfully on your Arduino IDE you can then be able to upload it on the Arduino module.</p><h3 id="how-to-install-arduino-ide-on-raspberry-pi-1" tabindex="-1">How to install Arduino IDE on Raspberry Pi <a class="header-anchor" href="#how-to-install-arduino-ide-on-raspberry-pi-1" aria-label="Permalink to &quot;How to install Arduino IDE on Raspberry Pi&quot;">​</a></h3><p>In this article, we will tell you how you can install Arduino IDE on Raspberry Pi by following the steps carefully. If you skip a step, you won’t be able to do your task on Arduino.</p><p><strong>Step 1:</strong> Check whether your system is updated or not. If your packages are not updated, any command you write to install a software will install an older version of the software. So, it is necessary for you to have installed the updates by entering the below command in the terminal.</p><p>$ sudo apt-get update</p><p><br><strong>Step 2:</strong> Now the first step is completed, you have to upgrade the packages as well using the given command in the terminal. This will upgrade your packages installed in your Raspberry Pi version.</p><figure><img src="https://linuxhint.com/wp-content/uploads/2022/01/image6-19.png" alt=""><figcaption></figcaption></figure><p>$ sudo apt-get upgrade</p><p><br><strong>Step 3:</strong> After installing all the important updates and upgrades, the next thing you should do is to install the Arduino IDE by entering the command in the terminal of your Raspberry Pi.</p><figure><img src="https://linuxhint.com/wp-content/uploads/2022/01/image8-16.png" alt=""><figcaption></figcaption></figure><p><a href="https://linuxhint.com/installing-esp32-arduino-ide-mac/" target="_blank" rel="noreferrer">Installing the ESP32 Board with Arduino IDE on Mac</a>40<a href="https://linuxhint.com/install-kdevelop-raspberry-pi/" target="_blank" rel="noreferrer">How to Install KDevelop on Raspberry Pi</a>65<a href="https://linuxhint.com/install-box86-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Box86 on Raspberry Pi</a>45<a href="https://linuxhint.com/install-git-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Git on Raspberry Pi</a>50<a href="https://linuxhint.com/install-netbeans-ide-linux-mint/" target="_blank" rel="noreferrer">How to Install Netbeans IDE on Linux Mint 21</a>8<a href="https://linuxhint.com/program-led-esp32-arduino-ide/" target="_blank" rel="noreferrer">How to Program ESP32 Using Arduino IDE to Blink an LED</a>57<a href="https://linuxhint.com/install-deb-file-raspberry-pi/" target="_blank" rel="noreferrer">How to Install deb File on Raspberry Pi</a>58<a href="https://linuxhint.com/install-powershell-raspberry-pi/" target="_blank" rel="noreferrer">How to Install PowerShell on Raspberry Pi</a>5<a href="https://linuxhint.com/install-musique-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Musique on Raspberry Pi</a>21<a href="https://linuxhint.com/install-microsoft-teams-32bit-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Microsoft Teams on 32Bit Raspberry Pi OS</a>33<a href="https://linuxhint.com/install-pidgin-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Pidgin on Raspberry Pi</a>54<a href="https://linuxhint.com/interface-lcd-esp32-arduino-ide/" target="_blank" rel="noreferrer">How to Interface LCD with ESP32 using Arduino IDE</a>78<a href="https://linuxhint.com/install-ffmpeg-raspberry-pi/" target="_blank" rel="noreferrer">How to Install FFmpeg on Raspberry Pi</a>49<a href="https://linuxhint.com/install-apache-tomcat-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Apache Tomcat on Raspberry Pi</a>78<a href="https://linuxhint.com/install-apache-pig-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Apache Pig on Raspberry Pi</a>45<a href="https://linuxhint.com/install-adminer-on-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Adminer on Raspberry Pi</a>32<a href="https://linuxhint.com/download-install-visual-novel-engine-renpy-raspberry-pi/" target="_blank" rel="noreferrer">How to download and install Visual Novel Engine Ren&#39;Py on Raspberry Pi</a>58<a href="https://linuxhint.com/install-monaco-editor-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Monaco Editor on Raspberry Pi</a>33<a href="https://linuxhint.com/install-empathy-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Empathy on Raspberry Pi</a>14<a href="https://linuxhint.com/install-use-veracrypt-raspberry-pi/" target="_blank" rel="noreferrer">How to Install and Use VeraCrypt on Raspberry Pi</a>24<a href="https://linuxhint.com/install-subsonic-media-server-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Subsonic Media Server on Raspberry Pi</a>13<a href="https://linuxhint.com/install-rpm-packages-raspberry-pi/" target="_blank" rel="noreferrer">How to Install RPM Packages on Raspberry Pi</a>25<a href="https://linuxhint.com/install-scala-raspberry-pi/" target="_blank" rel="noreferrer">How to Install and Use Scala on Raspberry Pi</a>42<a href="https://linuxhint.com/install-gnome-screenshot-utility-raspberry-pi/" target="_blank" rel="noreferrer">How to Install GNOME Screenshot Utility on Raspberry Pi</a>59<a href="https://linuxhint.com/install-openshot-video-editor-raspberry-pi/" target="_blank" rel="noreferrer">How to Install Openshot Video Editor on Raspberry Pi</a>53$ sudo apt install arduino</p><p><img src="https://linuxhint.com/wp-content/uploads/2022/01/image7-19.png" alt=""><br> The above command will install Arduino IDE on your Raspberry Pi desktop and you will be able to run it through the terminal by entering the following command.</p><p>$ arduino</p><p><img src="https://linuxhint.com/wp-content/uploads/2022/01/image10-10.png" alt=""></p><p>The above command will run the Arduino and you will be able to see it on your screen.</p><p><img src="https://linuxhint.com/wp-content/uploads/2022/01/image9-14.png" alt=""></p><h3 id="setting-up-your-arduino-ide" tabindex="-1">Setting up your Arduino IDE <a class="header-anchor" href="#setting-up-your-arduino-ide" aria-label="Permalink to &quot;Setting up your Arduino IDE&quot;">​</a></h3><p>After the installation, setting up your IDE is important so that you may be able to learn and understand how you can write code on Arduino IDE and how you can port it into the Arduino hardware. So, here are some steps you should check and understand:</p><p>You can run the Arduino IDE from the main menu option of the Raspberry Pi as well. For that you need to go to the main menu option and then in the programming option, you will be able to run Arduino by clicking on it.</p><p><img src="https://linuxhint.com/wp-content/uploads/2022/01/image2-38.png" alt=""><br> The latest version of Arduino IDE supports multiple board options. So, you don’t need to worry about the compatibility of your board with the Arduino IDE. You will find tons of options there. You can check your board by heading towards the tools option and then in the board option you will be able to see your required board in the list.</p><p><img src="https://linuxhint.com/wp-content/uploads/2022/01/image1-39.png" alt=""><br> If you want to test whether the Arduino is working fine or not but you don’t know how you can write a code. Then don’t need to worry about that as there are many examples available in Arduino, which you can easily select and run to check whether these are working fine on Arduino.</p><p>You can see those examples in the “File” option of Arduino IDE and then heading towards the “Examples” option. There you will be able to see a lot of examples which you can run on your IDE.</p><p><img src="https://linuxhint.com/wp-content/uploads/2022/01/image4-28.png" alt=""><br> Now you can easily verify whether the code is working fine or not by selecting the first option “Verify”. It will give you a confirmation message then your code is successfully compiled without any error.</p><p><img src="https://linuxhint.com/wp-content/uploads/2022/01/image3-33.png" alt=""><br> If you want to port your code with your Arduino board you can do that easily after the compilation and by clicking on the “Upload” option. But for that you first need to connect your board with your system otherwise it will give you an error message saying that your serial port “COM1” is not found.</p><h3 id="uninstalling-arduino-ide-on-raspberry-pi" tabindex="-1">Uninstalling Arduino IDE on Raspberry Pi <a class="header-anchor" href="#uninstalling-arduino-ide-on-raspberry-pi" aria-label="Permalink to &quot;Uninstalling Arduino IDE on Raspberry Pi&quot;">​</a></h3><p>If you are wishing to remove Arduino IDE on Raspberry Pi, you can do that quite easily through entering a simple command in the terminal.</p><p>$ sudo apt-get remove arduino</p><p><img src="https://linuxhint.com/wp-content/uploads/2022/01/image5-22.png" alt=""></p><h3 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h3><p>If you are really interested in testing your skills on the Arduino IDE on Raspberry Pi, this is your best chance to get what you really want. The installation of Arduino IDE on Raspberry Pi is just a few steps away from you and if you successfully install it then you will be able to start your professional journey by writing codes on Arduino IDE.</p>',34)])])}const y=r(a,[["render",i]]);export{c as __pageData,y as default};
